SELECT s.order_id AS orderId, s.sample_id AS sampleId, MAX(s.produce_id) AS produceId, COUNT(*) AS templateNumber, MAX(c.customer_name) AS customerName, MAX(c.address) AS customerAddress, MAX(s.sample_type) AS sampleType, MAX(s.primer) AS primer, MAX(s.primer_concentration) AS primerConcentration, MAX(s.carrier_name) AS carrierName, MAX(s.antibiotic_type) AS antibioticType, MAX(s.fragment_size) AS fragmentSize, MAX(s.test_result) AS testResult, MAX(s.origin_concentration) AS originConcentration, MAX(s.template_plate_no) AS templatePlateNo, MAX(s.template_hole_no) AS templateHoleNo, MAX(s.performance) AS performance, MAX(s.return_state) AS returnState, MAX(s.flow_name) AS flowName, MAX(s.create_user) AS createUser, MAX(s.origin_hole_no) AS originHoleNo, MAX(s.belong_lab) AS belongLab, MAX(s.report_status) AS reportStatus, MAX(s.report_error_reason) AS reportErrorReason, MAX(s.remark) AS remark FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id where flow_name = '0'
AND s.order_id = #{query.orderId}
AND s.sample_id = #{query.sampleId}
AND c.customer_name LIKE CONCAT('%', #{query.customerName}, '%')
AND s.return_state = #{query.returnState}
GROUP BY s.order_id, s.sample_id ORDER BY MAX(s.create_time) DESC

SELECT s.order_id AS orderId, s.produce_id AS produceId, c.customer_name AS customerName, c.address AS customerAddress, s.sample_id AS sampleId, s.sample_type AS sampleType, s.primer AS primer, s.primer_concentration AS primerConcentration, s.carrier_name AS carrierName, s.antibiotic_type AS antibioticType, s.fragment_size AS fragmentSize, s.test_result AS testResult, s.origin_concentration AS originConcentration, s.template_plate_no AS templatePlateNo, s.template_hole_no AS templateHoleNo, s.performance AS performance, s.return_state AS returnState, s.flow_name AS flowName, s.create_user AS createUser, s.origin_hole_no AS originHoleNo, s.belong_lab AS belongLab, s.report_status AS reportStatus, s.report_error_reason AS reportErrorReason, s.remark AS remark FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id where flow_name = #{query.flowName}
AND s.order_id = #{query.orderId}
AND s.produce_id = #{query.produceId}
AND s.sample_id = #{query.sampleId}
AND c.customer_name LIKE CONCAT('%', #{query.customerName}, '%')
AND s.create_user like CONCAT('%', #{query.createUser},'%')
AND s.sample_type like CONCAT('%', #{query.sampleType},'%')
AND s.template_plate_no like CONCAT('%', #{query.templateNo},'%')
ORDER BY s.create_time DESC

SELECT c.customer_name AS customerName, s.produce_id AS produceId, s.sample_id AS sampleId, s.fragment_size AS fragmentSize FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id
AND s.order_id >= #{req.startOrderNo}
AND s.order_id <= #{req.endOrderNo}
AND s.belong_company = #{req.belongCompany}
ORDER BY s.order_id, s.sample_id

SELECT s.produce_id AS produceId, s.origin_hole_no AS originHoleNo, c.customer_name AS customerName, s.return_state AS returnState, s.sample_type AS sampleType, s.sample_id AS sampleId, s.carrier_name AS carrierName, s.antibiotic_type AS antibioticType, s.sample_position AS samplePosition, s.belong_lab AS belongLab, s.report_status AS reportStatus, s.remark AS remark FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id
AND s.return_state IN ('模板重抽', '报告重抽')
AND s.template_plate_no IN
#{plateNo}
AND s.belong_lab = #{req.belongLab}
ORDER BY s.template_plate_no, s.template_hole_no
